import re

def evaluate(expr: str) -> float:
    expr_stripped = expr.strip()
    if not expr_stripped:
        raise ValueError()

    tokens = []
    i = 0
    while i < len(expr):
        if expr[i].isspace():
            i += 1
        elif expr[i:i+2] == '**':
            tokens.append('**')
            i += 2
        elif expr[i] in '+-*/()':
            tokens.append(expr[i])
            i += 1
        else:
            match = re.match(r'\d+\.?\d*|\.\d+', expr[i:])
            if match:
                tokens.append(float(match.group()))
                i += len(match.group())
            else:
                raise ValueError()

    if not tokens:
        raise ValueError()

    class Parser:
        def __init__(self, tokens):
            self.tokens = tokens
            self.pos = 0

        def current(self):
            if self.pos < len(self.tokens):
                return self.tokens[self.pos]
            return None

        def consume(self):
            token = self.current()
            self.pos += 1
            return token

        def parse_unary(self):
            if self.current() == '-':
                self.consume()
                operand = self.parse_unary()
                return -operand
            elif self.current() == '+':
                self.consume()
                return self.parse_unary()
            return self.parse_additive()

        def parse_additive(self):
            left = self.parse_multiplicative()
            while self.current() in ('+', '-'):
                op = self.consume()
                right = self.parse_multiplicative()
                if op == '+':
                    left = left + right
                else:
                    left = left - right
            return left

        def parse_multiplicative(self):
            left = self.parse_exponent()
            while self.current() in ('*', '/'):
                op = self.consume()
                right = self.parse_exponent()
                if op == '*':
                    left = left * right
                else:
                    if right == 0:
                        raise ZeroDivisionError()
                    left = left / right
            return left

        def parse_exponent(self):
            left = self.parse_atom()
            if self.current() == '**':
                self.consume()
                right = self.parse_unary()
                left = left ** right
            return left

        def parse_atom(self):
            if self.current() == '(':
                self.consume()
                result = self.parse_unary()
                if self.current() != ')':
                    raise ValueError()
                self.consume()
                return result
            elif isinstance(self.current(), (int, float)):
                return self.consume()
            else:
                raise ValueError()

    parser = Parser(tokens)
    result = parser.parse_unary()
    if parser.pos < len(tokens):
        raise ValueError()
    return result
